  1→package mcp
  2→
  3→import (
  4→	"context"
  5→	"fmt"
  6→	"log/slog"
  7→	"strings"
  8→
  9→	"github.com/google/uuid"
 10→	mcpgo "github.com/mark3labs/mcp-go/mcp"
 11→	"github.com/mark3labs/mcp-go/server"
 12→
 13→	"github.com/ketang/flotsam/api/internal/auth"
 14→	"github.com/ketang/flotsam/api/internal/audit"
 15→	"github.com/ketang/flotsam/api/internal/item"
 16→)
 17→
 18→const (
 19→	defaultSearchLimit     = 10
 20→	maxSearchLimit         = 50
 21→	defaultSearchThreshold = 0.3
 22→)
 23→
 24→// --- search tool ---
 25→
 26→func searchTool() mcpgo.Tool {
 27→	return mcpgo.NewTool("search",
 28→		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
 29→		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
 30→		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
 31→		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
 32→	)
 33→}
 34→
 35→func searchHandler(deps Deps) server.ToolHandlerFunc {
 36→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 37→		claims, errResult := requireAuth(ctx)
 38→		if errResult != nil {
 39→			return errResult, nil
 40→		}
 41→
 42→		if errResult := AllowedTool(ctx, "search"); errResult != nil {
 43→			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), true)
 44→			return errResult, nil
 45→		}
 46→
 47→		query := req.GetString("query", "")
 48→		if query == "" {
 49→			return mcpgo.NewToolResultError("query is required"), nil
 50→		}
 51→
 52→		limit := req.GetInt("limit", defaultSearchLimit)
 53→		if limit < 1 {
 54→			limit = 1
 55→		}
 56→		if limit > maxSearchLimit {
 57→			limit = maxSearchLimit
 58→		}
 59→
 60→		var filter *item.Filter
 61→		if t := req.GetString("type", ""); t != "" {
 62→			filter = &item.Filter{Types: []string{t}}
 63→		}
 64→
 65→		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
 66→		if err != nil {
 67→			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
 68→			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
 69→		}
 70→
 71→		// Filter results by sensitivity
 72→		result = FilterItemsBySensitivity(ctx, result)
 73→
 74→		auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
 75→		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
 76→	}
 77→}
 78→
 79→// doSearch tries semantic search first, falling back to full-text search.
 80→func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
 81→	if deps.Embedder != nil {
 82→		embedding, err := deps.Embedder.Embed(ctx, query)
 83→		if err != nil {
 84→			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
 85→		} else {
 86→			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
 87→			if err == nil && len(result.Items) > 0 {
 88→				return result, nil
 89→			}
 90→			if err != nil {
 91→				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
 92→			}
 93→		}
 94→	}
 95→
 96→	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
 97→}
 98→
 99→// --- browse tool ---
100→
101→func browseTool() mcpgo.Tool {
102→	return mcpgo.NewTool("browse",
103→		mcpgo.WithDescription("Get the full content of an item by its ID."),
104→		mcpgo.WithString("id", mcpgo.Required(), mcpgo.Description("Item UUID")),
105→	)
106→}
107→
108→func browseHandler(deps Deps) server.ToolHandlerFunc {
109→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
110→		claims, errResult := requireAuth(ctx)
111→		if errResult != nil {
112→			return errResult, nil
113→		}
114→
115→		if errResult := AllowedTool(ctx, "browse"); errResult != nil {
116→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
117→			return errResult, nil
118→		}
119→
120→		idStr := req.GetString("id", "")
121→		id, err := uuid.Parse(idStr)
122→		if err != nil {
123→			return mcpgo.NewToolResultError("invalid item ID: must be a valid UUID"), nil
124→		}
125→
126→		it, err := deps.Items.GetByID(ctx, claims.UserID, id)
127→		if err != nil {
128→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
129→			return mcpgo.NewToolResultError(fmt.Sprintf("failed to get item: %v", err)), nil
130→		}
131→
132→		// Check sensitivity
133→		if !SensitivityAllowed(ctx, it.Sensitivity) {
134→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
135→			return mcpgo.NewToolResultError("item sensitivity level exceeds API key permissions"), nil
136→		}
137→
138→		auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
139→		return mcpgo.NewToolResultText(formatItem(it)), nil
140→	}
141→}
142→
143→// --- capture tool ---
144→
145→func captureTool() mcpgo.Tool {
146→	return mcpgo.NewTool("capture",
147→		mcpgo.WithDescription("Capture a new item into your knowledge base. Provide 'url' for a bookmark or 'content' for a note."),
148→		mcpgo.WithString("url", mcpgo.Description("URL to bookmark")),
149→		mcpgo.WithString("content", mcpgo.Description("Text content for a note")),
150→		mcpgo.WithString("title", mcpgo.Description("Optional title")),
151→		mcpgo.WithString("tags", mcpgo.Description("Comma-separated tags")),
152→		mcpgo.WithString("sensitivity", mcpgo.Description("Sensitivity level"), mcpgo.Enum("normal", "sensitive")),
153→	)
154→}
155→
156→func captureHandler(deps Deps) server.ToolHandlerFunc {
157→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
158→		claims, errResult := requireAuth(ctx)
159→		if errResult != nil {
160→			return errResult, nil
161→		}
162→
163→		if errResult := AllowedTool(ctx, "capture"); errResult != nil {
164→			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), true)
165→			return errResult, nil
166→		}
167→
168→		url := req.GetString("url", "")
169→		content := req.GetString("content", "")
170→		titleStr := req.GetString("title", "")
171→		tagsStr := req.GetString("tags", "")
172→		sensitivity := req.GetString("sensitivity", "normal")
173→
174→		var title *string
175→		if titleStr != "" {
176→			title = &titleStr
177→		}
178→
179→		var tags []string
180→		if tagsStr != "" {
181→			for _, t := range strings.Split(tagsStr, ",") {
182→				t = strings.TrimSpace(t)
183→				if t != "" {
184→					tags = append(tags, t)
185→				}
186→			}
187→		}
188→
189→		switch {
190→		case url != "":
191→			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
192→				URL:         url,
193→				Title:       title,
194→				Tags:        tags,
195→				Sensitivity: sensitivity,
196→				Source:      "mcp",
197→			})
198→			if err != nil {
199→				auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
200→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
201→			}
202→			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
203→			return mcpgo.NewToolResultText(formatItem(it)), nil
204→
205→		case content != "":
206→			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
207→				Title:       title,
208→				Content:     content,
209→				Tags:        tags,
210→				Sensitivity: sensitivity,
211→				Source:      "mcp",
212→			})
213→			if err != nil {
214→				auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
215→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
216→			}
217→			auditToolCall(ctx, deps.Audit, claims, "capture", req.GetArguments(), false)
218→			return mcpgo.NewToolResultText(formatItem(it)), nil
219→
220→		default:
221→			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
222→		}
223→	}
224→}
225→
226→// auditToolCall logs a tool invocation to the audit log (best effort).
227→func auditToolCall(ctx context.Context, logger *audit.Logger, claims *auth.Claims, tool string, args map[string]any, denied bool) {
228→	if logger == nil {
229→		return
230→	}
231→
232→	client := auth.GetMCPClient(ctx)
233→	var clientID *uuid.UUID
234→	if client != nil {
235→		clientID = &client.ClientID
236→	}
237→
238→	var approved *bool
239→	if denied {
240→		f := false
241→		approved = &f
242→	}
243→
244→	logger.Log(ctx, audit.Entry{
245→		UserID:       claims.UserID,
246→		ClientID:     clientID,
247→		Action:       "mcp." + tool,
248→		ResourceType: "tool",
249→		Request:      args,
250→		Approved:     approved,
251→	})
252→}
