 1→package mcp
 2→
 3→import (
 4→	"context"
 5→	"fmt"
 6→
 7→	mcpgo "github.com/mark3labs/mcp-go/mcp"
 8→
 9→	"github.com/ketang/flotsam/api/internal/auth"
10→	"github.com/ketang/flotsam/api/internal/item"
11→)
12→
13→// sensitivityRank maps sensitivity levels to numeric ranks for comparison.
14→var sensitivityRank = map[string]int{
15→	"normal":    0,
16→	"sensitive": 1,
17→	"private":   2,
18→}
19→
20→// AllowedTool checks whether the MCP client (if present) is permitted to call
21→// the named tool. JWT-authenticated requests (no MCPClientInfo) are always allowed.
22→func AllowedTool(ctx context.Context, toolName string) *mcpgo.CallToolResult {
23→	client := auth.GetMCPClient(ctx)
24→	if client == nil {
25→		return nil // JWT auth — no restrictions
26→	}
27→
28→	// Empty tool list means "all tools allowed"
29→	if len(client.Tools) == 0 {
30→		return nil
31→	}
32→
33→	for _, t := range client.Tools {
34→		if t == toolName {
35→			return nil
36→		}
37→	}
38→
39→	return mcpgo.NewToolResultError(fmt.Sprintf("tool %q not permitted for this API key", toolName))
40→}
41→
42→// SensitivityAllowed returns true if the given sensitivity level is within the
43→// client's maximum. JWT-authenticated requests are unrestricted. Private items
44→// are NEVER returned via MCP regardless of client configuration.
45→func SensitivityAllowed(ctx context.Context, sensitivity string) bool {
46→	// Private items are never returned via MCP
47→	if sensitivity == "private" {
48→		return false
49→	}
50→
51→	client := auth.GetMCPClient(ctx)
52→	if client == nil {
53→		return true // JWT auth — allow everything except private
54→	}
55→
56→	maxSensitivity := client.MaxSensitivity
57→	if maxSensitivity == "" {
58→		maxSensitivity = "normal"
59→	}
60→
61→	return sensitivityRank[sensitivity] <= sensitivityRank[maxSensitivity]
62→}
63→
64→// FilterItemsBySensitivity removes items that exceed the client's sensitivity
65→// limit from a search result.
66→func FilterItemsBySensitivity(ctx context.Context, result *item.SearchResult) *item.SearchResult {
67→	filtered := make([]*item.Item, 0, len(result.Items))
68→	for _, it := range result.Items {
69→		if SensitivityAllowed(ctx, it.Sensitivity) {
70→			filtered = append(filtered, it)
71→		}
72→	}
73→	return &item.SearchResult{
74→		Items:   filtered,
75→		Total:   len(filtered),
76→		HasMore: result.HasMore,
77→	}
78→}
79→

 1→package mcp
 2→
 3→import (
 4→	"fmt"
 5→	"strings"
 6→
 7→	"github.com/ketang/flotsam/api/internal/item"
 8→)
 9→
10→const maxSnippetLen = 500
11→
12→// formatSearchResults renders a search result set as markdown text.
13→func formatSearchResults(result *item.SearchResult) string {
14→	if len(result.Items) == 0 {
15→		return "No items found."
16→	}
17→
18→	var b strings.Builder
19→	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)
20→
21→	for _, it := range result.Items {
22→		b.WriteString(formatItemSummary(it))
23→		b.WriteString("\n")
24→	}
25→
26→	if result.HasMore {
27→		b.WriteString("_(more results available — increase limit or refine query)_\n")
28→	}
29→
30→	return b.String()
31→}
32→
33→// formatItemSummary renders a single item as a compact summary line.
34→func formatItemSummary(it *item.Item) string {
35→	var b strings.Builder
36→
37→	title := it.ID.String()
38→	if it.Title != nil && *it.Title != "" {
39→		title = *it.Title
40→	}
41→
42→	fmt.Fprintf(&b, "- **%s** [%s] (id: %s)", title, it.Type, it.ID)
43→
44→	if len(it.Tags) > 0 {
45→		fmt.Fprintf(&b, " tags: %s", strings.Join(it.Tags, ", "))
46→	}
47→
48→	if it.ContentText != nil && *it.ContentText != "" {
49→		snippet := *it.ContentText
50→		if len(snippet) > maxSnippetLen {
51→			snippet = snippet[:maxSnippetLen] + "..."
52→		}
53→		fmt.Fprintf(&b, "\n  > %s", strings.ReplaceAll(snippet, "\n", "\n  > "))
54→	}
55→
56→	b.WriteString("\n")
57→	return b.String()
58→}
59→
60→// formatItem renders a full item as detailed markdown.
61→func formatItem(it *item.Item) string {
62→	var b strings.Builder
63→
64→	title := it.ID.String()
65→	if it.Title != nil && *it.Title != "" {
66→		title = *it.Title
67→	}
68→
69→	fmt.Fprintf(&b, "# %s\n\n", title)
70→	fmt.Fprintf(&b, "- **ID:** %s\n", it.ID)
71→	fmt.Fprintf(&b, "- **Type:** %s\n", it.Type)
72→	fmt.Fprintf(&b, "- **Status:** %s\n", it.Status)
73→	fmt.Fprintf(&b, "- **Sensitivity:** %s\n", it.Sensitivity)
74→	fmt.Fprintf(&b, "- **Source:** %s\n", it.Source)
75→	fmt.Fprintf(&b, "- **Captured:** %s\n", it.CapturedAt.Format("2006-01-02 15:04:05"))
76→
77→	if len(it.Tags) > 0 {
78→		fmt.Fprintf(&b, "- **Tags:** %s\n", strings.Join(it.Tags, ", "))
79→	}
80→
81→	if it.SourceURL != nil && *it.SourceURL != "" {
82→		fmt.Fprintf(&b, "- **URL:** %s\n", *it.SourceURL)
83→	}
84→
85→	if it.ContentURL != nil && *it.ContentURL != "" {
86→		fmt.Fprintf(&b, "- **Content URL:** %s\n", *it.ContentURL)
87→	}
88→
89→	if it.ContentText != nil && *it.ContentText != "" {
90→		fmt.Fprintf(&b, "\n## Content\n\n%s\n", *it.ContentText)
91→	}
92→
93→	return b.String()
94→}
