 16→func TestRequireAuth(t *testing.T) {
 17→	t.Run("no claims returns UNAUTHENTICATED gqlerror", func(t *testing.T) {
 18→		_, err := requireAuth(context.Background())
 19→		if err == nil {
 20→			t.Fatal("expected error")
 21→		}
 22→		gqlErr, ok := err.(*gqlerror.Error)
 23→		if !ok {
 24→			t.Fatalf("expected *gqlerror.Error, got %T", err)
 25→		}
 26→		if gqlErr.Message != "authentication required" {
 27→			t.Errorf("message = %q, want %q", gqlErr.Message, "authentication required")
 28→		}
 29→		if code, _ := gqlErr.Extensions["code"].(string); code != "UNAUTHENTICATED" {
 30→			t.Errorf("extensions.code = %q, want %q", code, "UNAUTHENTICATED")
 31→		}
 32→	})
 33→
 34→	t.Run("with claims succeeds", func(t *testing.T) {
 35→		claims := &auth.Claims{UserID: uuid.New(), Email: "test@example.com"}
 36→		ctx := auth.WithClaims(context.Background(), claims)
 37→		got, err := requireAuth(ctx)
 38→		if err != nil {
 39→			t.Fatalf("unexpected error: %v", err)
 40→		}
 41→		if got.UserID != claims.UserID {
 42→			t.Errorf("expected UserID %v, got %v", claims.UserID, got.UserID)
 43→		}
 44→	})
 45→}
