 47→func TestToGraphQLItem(t *testing.T) {
 48→	title := "Test Title"
 49→	contentText := "Some content"
 50→	contentURL := "https://example.com"
 51→	sourceURL := "https://referrer.com"
 52→	now := time.Now().UTC().Truncate(time.Millisecond)
 53→
 54→	it := &item.Item{
 55→		ID:           uuid.New(),
 56→		OwnerID:      uuid.New(),
 57→		Type:         "bookmark",
 58→		Status:       "ready",
 59→		Sensitivity:  "normal",
 60→		Title:        &title,
 61→		ContentText:  &contentText,
 62→		ContentURL:   &contentURL,
 63→		Tags:         []string{"go", "test"},
 64→		Metadata:     map[string]any{"key": "val"},
 65→		AutoMetadata: map[string]any{"auto": true},
 66→		Source:       "chrome_extension",
 67→		SourceURL:    &sourceURL,
 68→		CreatedAt:    now,
 69→		UpdatedAt:    now,
 70→		CapturedAt:   now,
 71→	}
 72→
 73→	result := toGraphQLItem(it)
 74→
 75→	if result.ID != it.ID.String() {
 76→		t.Errorf("ID mismatch: %s vs %s", result.ID, it.ID.String())
 77→	}
 78→	if result.Type != model.ItemTypeBookmark {
 79→		t.Errorf("Type = %v, want BOOKMARK", result.Type)
 80→	}
 81→	if result.Status != model.ItemStatusReady {
 82→		t.Errorf("Status = %v, want READY", result.Status)
 83→	}
 84→	if result.Sensitivity != model.SensitivityLevelNormal {
 85→		t.Errorf("Sensitivity = %v, want NORMAL", result.Sensitivity)
 86→	}
 87→	if *result.Title != title {
 88→		t.Errorf("Title = %v, want %v", *result.Title, title)
 89→	}
 90→	if *result.ContentText != contentText {
 91→		t.Errorf("ContentText mismatch")
 92→	}
 93→	if *result.ContentURL != contentURL {
 94→		t.Errorf("ContentURL mismatch")
 95→	}
 96→	if len(result.Tags) != 2 {
 97→		t.Errorf("Tags length = %d, want 2", len(result.Tags))
 98→	}
 99→	if result.Source != "chrome_extension" {
100→		t.Errorf("Source = %q, want 'chrome_extension'", result.Source)
101→	}
102→	if *result.SourceURL != sourceURL {
103→		t.Errorf("SourceURL mismatch")
104→	}
105→	if !result.CreatedAt.Equal(now) {
106→		t.Errorf("CreatedAt mismatch")
107→	}
108→}
