package mcp

import (
	"fmt"
	"strings"

	"github.com/ketang/flotsam/api/internal/item"
)

const maxSnippetLen = 500

// formatSearchResults renders a search result set as markdown text.
func formatSearchResults(result *item.SearchResult) string {
	if len(result.Items) == 0 {
		return "No items found."
	}

	var b strings.Builder
	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)

	for _, it := range result.Items {
		b.WriteString(formatItemSummary(it))
		b.WriteString("\n")
	}

	if result.HasMore {
		b.WriteString("_(more results available — increase limit or refine query)_\n")
	}

	return b.String()
}

// formatItemSummary renders a single item as a compact summary line.
func formatItemSummary(it *item.Item) string {
	var b strings.Builder

	title := it.ID.String()
	if it.Title != nil && *it.Title != "" {
		title = *it.Title
	}

	fmt.Fprintf(&b, "- **%s** [%s] (id: %s)", title, it.Type, it.ID)

	if len(it.Tags) > 0 {
		fmt.Fprintf(&b, " tags: %s", strings.Join(it.Tags, ", "))
	}

	if it.ContentText != nil && *it.ContentText != "" {
		snippet := *it.ContentText
		if len(snippet) > maxSnippetLen {
			snippet = snippet[:maxSnippetLen] + "..."
		}
		fmt.Fprintf(&b, "\n  > %s", strings.ReplaceAll(snippet, "\n", "\n  > "))
	}

	b.WriteString("\n")
	return b.String()
}

// formatItem renders a full item as detailed markdown.
func formatItem(it *item.Item) string {
	var b strings.Builder

	title := it.ID.String()
	if it.Title != nil && *it.Title != "" {
		title = *it.Title
	}

	fmt.Fprintf(&b, "# %s\n\n", title)
	fmt.Fprintf(&b, "- **ID:** %s\n", it.ID)
	fmt.Fprintf(&b, "- **Type:** %s\n", it.Type)
	fmt.Fprintf(&b, "- **Status:** %s\n", it.Status)
	fmt.Fprintf(&b, "- **Sensitivity:** %s\n", it.Sensitivity)
	fmt.Fprintf(&b, "- **Source:** %s\n", it.Source)
	fmt.Fprintf(&b, "- **Captured:** %s\n", it.CapturedAt.Format("2006-01-02 15:04:05"))

	if len(it.Tags) > 0 {
		fmt.Fprintf(&b, "- **Tags:** %s\n", strings.Join(it.Tags, ", "))
	}

	if it.SourceURL != nil && *it.SourceURL != "" {
		fmt.Fprintf(&b, "- **URL:** %s\n", *it.SourceURL)
	}

	if it.ContentURL != nil && *it.ContentURL != "" {
		fmt.Fprintf(&b, "- **Content URL:** %s\n", *it.ContentURL)
	}

	if it.ContentText != nil && *it.ContentText != "" {
		fmt.Fprintf(&b, "\n## Content\n\n%s\n", *it.ContentText)
	}

	return b.String()
}

