import { test, expect } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'

const API_BASE = 'http://localhost:8081'

/** Send a JSON-RPC 2.0 request to the MCP endpoint. */
async function mcpCall(
  request: import('@playwright/test').APIRequestContext,
  token: string,
  id: string,
  method: string,
  params?: Record<string, unknown>,
) {
  const body: Record<string, unknown> = {
    jsonrpc: '2.0',
    id,
    method,
  }
  if (params) body.params = params

  const response = await request.post(`${API_BASE}/mcp/`, {
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    data: body,
  })
  return response
}

test.describe('MCP Walkthrough', () => {
  let token: string

  test.beforeAll(async ({ request }) => {
    // Authenticate via GraphQL login mutation
    const loginRes = await request.post(`${API_BASE}/graphql`, {
      data: {
        query: `mutation { login(input: { email: "ketan@example.com", password: "testpassword123" }) { token } }`,
      },
    })
    expect(loginRes.ok()).toBeTruthy()

    const loginJson = await loginRes.json()
    token = loginJson.data.login.token
    expect(token).toBeTruthy()

    if (isManual) console.log('[MCP] Authenticated — token:', token.slice(0, 20) + '...')
  })

  test('Initialize MCP session', async ({ request }) => {
    const res = await mcpCall(request, token, 'init-1', 'initialize', {
      protocolVersion: '2025-03-26',
      capabilities: {},
      clientInfo: { name: 'flotsam-demo', version: '0.1.0' },
    })
    expect(res.ok()).toBeTruthy()

    const json = await res.json()
    expect(json.result).toBeTruthy()
    expect(json.result.serverInfo.name).toBe('flotsam')

    if (isManual) console.log('[MCP] Server info:', JSON.stringify(json.result.serverInfo, null, 2))
  })

  test('Search for known items', async ({ request }) => {
    const res = await mcpCall(request, token, 'search-1', 'tools/call', {
      name: 'search',
      arguments: { query: 'distributed systems', limit: 5 },
    })
    expect(res.ok()).toBeTruthy()

    const json = await res.json()
    expect(json.result).toBeTruthy()
    expect(json.result.isError).toBeFalsy()

    const text: string = json.result.content[0].text
    expect(text).toContain('Found')
    expect(text).toContain('Distributed Systems')

    if (isManual) console.log('[MCP] Search results:\n' + text)
  })

  test('Browse a known item from search results', async ({ request }) => {
    // First search to get an item ID
    const searchRes = await mcpCall(request, token, 'search-2', 'tools/call', {
      name: 'search',
      arguments: { query: 'sourdough', limit: 5 },
    })
    expect(searchRes.ok()).toBeTruthy()

    const searchJson = await searchRes.json()
    const searchText: string = searchJson.result.content[0].text
    expect(searchText).toContain('Sourdough')

    // Extract UUID from search result text: (id: <uuid>)
    const idMatch = searchText.match(/\(id:\s*([0-9a-f-]{36})\)/)
    expect(idMatch).toBeTruthy()
    const itemId = idMatch![1]

    if (isManual) console.log('[MCP] Browsing item:', itemId)

    // Browse the item
    const browseRes = await mcpCall(request, token, 'browse-1', 'tools/call', {
      name: 'browse',
      arguments: { id: itemId },
    })
    expect(browseRes.ok()).toBeTruthy()

    const browseJson = await browseRes.json()
    expect(browseJson.result.isError).toBeFalsy()

    const browseText: string = browseJson.result.content[0].text

    // Verify item details are present
    expect(browseText).toContain('Sourdough')
    expect(browseText).toContain('**Type:**')
    expect(browseText).toContain('**ID:**')
    expect(browseText).toContain('## Content')

    if (isManual) console.log('[MCP] Browse result:\n' + browseText)
  })
})

